SELECT

FROM model_invocation_log

    tenant_id = #{query.tenantId}

        AND session_id = #{query.sessionId}


        AND model_registry_id = #{query.modelRegistryId}


        AND provider = #{query.provider}


        AND request_id = #{query.requestId}


        AND status = #{query.status}


        AND created_at >= #{query.from}


        AND created_at <= #{query.to}


ORDER BY created_at DESC, id DESC
LIMIT #{limit}
OFFSET #{offset}

SELECT COUNT(1)
FROM model_invocation_log

    tenant_id = #{query.tenantId}

        AND session_id = #{query.sessionId}


        AND model_registry_id = #{query.modelRegistryId}


        AND provider = #{query.provider}


        AND request_id = #{query.requestId}


        AND status = #{query.status}


        AND created_at >= #{query.from}


        AND created_at <= #{query.to}
